+    #[test]
+    fn writer_multiple_deletes() {
+        let dir = tempdir().unwrap();
+        let config = test_config(dir.path());
+        let indexer = LexicalIndexer::open(config).unwrap();
+
+        let mut writer = indexer.create_writer_with_memory(15_000_000).unwrap();
+
